import{_ as a,c as s,o as e,a as t}from"./app.3fdcf20e.js";const m=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[{"level":2,"title":"Supported Systems","slug":"supported-systems","link":"#supported-systems","children":[]},{"level":2,"title":"Automated Install","slug":"automated-install","link":"#automated-install","children":[]},{"level":2,"title":"Manual Build","slug":"manual-build","link":"#manual-build","children":[]},{"level":2,"title":"Update","slug":"update","link":"#update","children":[]},{"level":2,"title":"Uninstall","slug":"uninstall","link":"#uninstall","children":[]},{"level":2,"title":"Prerequisites","slug":"prerequisites","link":"#prerequisites","children":[]}],"relativePath":"openshield-xdp/guide/installation.md","lastUpdated":1782412920000}'),l={name:"openshield-xdp/guide/installation.md"},n=t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-hidden="true">#</a></h1><h2 id="supported-systems" tabindex="-1">Supported Systems <a class="header-anchor" href="#supported-systems" aria-hidden="true">#</a></h2><table><thead><tr><th>OS</th><th>Package Managers</th></tr></thead><tbody><tr><td>Ubuntu 22.04+</td><td>apt</td></tr><tr><td>Debian 12+</td><td>apt</td></tr><tr><td>Fedora 38+</td><td>dnf</td></tr><tr><td>RHEL 9+ / Rocky / Alma</td><td>dnf / yum</td></tr><tr><td>Arch Linux</td><td>pacman</td></tr><tr><td>Alpine Linux</td><td>apk</td></tr><tr><td>openSUSE</td><td>zypper</td></tr></tbody></table><h2 id="automated-install" tabindex="-1">Automated Install <a class="header-anchor" href="#automated-install" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">git clone https://github.com/AnAverageBeing/OpenShield-XDP.git</span></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> OpenShield-XDP</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo ./install.sh</span></span>
<span class="line"></span></code></pre></div><p>Installs clang, llvm, bpftool, libbpf, Go (if missing), compiles BPF + Go, generates config, sets up systemd service. Runs <code>openshield fix</code> as a post-install step.</p><h2 id="manual-build" tabindex="-1">Manual Build <a class="header-anchor" href="#manual-build" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">make vmlinux     </span><span style="color:#676E95;"># Generate vmlinux.h from /sys/kernel/btf/vmlinux (first time)</span></span>
<span class="line"><span style="color:#A6ACCD;">make all         </span><span style="color:#676E95;"># BPF + bpf2go bindings + Go userspace</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo make install</span></span>
<span class="line"></span></code></pre></div><h2 id="update" tabindex="-1">Update <a class="header-anchor" href="#update" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">git pull</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo ./install.sh --update</span></span>
<span class="line"></span></code></pre></div><h2 id="uninstall" tabindex="-1">Uninstall <a class="header-anchor" href="#uninstall" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">sudo ./install.sh --uninstall</span></span>
<span class="line"></span></code></pre></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-hidden="true">#</a></h2><ul><li>Linux kernel \u2265 5.8 (\u2265 5.11 for freplace)</li><li><code>CONFIG_DEBUG_INFO_BTF=y</code></li><li>XDP-capable NIC driver</li></ul>`,14),i=[n];function d(p,r,o,c,u,h){return e(),s("div",null,i)}const g=a(l,[["render",d]]);export{m as __pageData,g as default};
